parameters.functionCode:
// Filter bookings for today and group by provider
const today = new Date();
today.setHours(0, 0, 0, 0);

const allBookings = items.map(item => item.json);

// Filter for today's confirmed bookings
const todayBookings = allBookings.filter(booking => {
  const bookingDate = new Date(booking.tourDate);
  bookingDate.setHours(0, 0, 0, 0);
  return bookingDate.getTime() === today.getTime() && 
         booking.status === 'confirmed';
});

// Group by provider
const providerBookings = {};

todayBookings.forEach(booking => {
  const providerId = booking.providerId || booking.providerName;

  if (!providerBookings[providerId]) {
    providerBookings[providerId] = {
      providerId: providerId,
      providerName: booking.providerName,
      providerEmail: booking.providerEmail,
      bookings: [],
      totalCustomers: 0,
      tours: {}
    };
  }

  providerBookings[providerId].bookings.push(booking);
  providerBookings[providerId].totalCustomers += parseInt(booking.numberOfPeople) || 1;

  // Count by tour
  const tourName = booking.tourName;
  if (!providerBookings[providerId].tours[tourName]) {
    providerBookings[providerId].tours[tourName] = {
      tourName: tourName,
      bookingCount: 0,
      totalGuests: 0
    };
  }
  providerBookings[providerId].tours[tourName].bookingCount++;
  providerBookings[providerId].tours[tourName].totalGuests += parseInt(booking.numberOfPeople) || 1;
});

// Convert to array and add summary
const results = Object.values(providerBookings).map(provider => {
  return {
    ...provider,
    tourSummary: Object.values(provider.tours),
    hasBookings: provider.bookings.length > 0,
    date: today.toLocaleDateString('en-US', { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    }),
    reportGeneratedTime: new Date().toLocaleString()
  };
});

return results.map(r => ({ json: r }));

