parameters.functionCode:
// Prepare admin summary of all providers
const allProviders = items.map(item => item.json);

const totalBookings = allProviders.reduce((sum, p) => sum + p.bookings.length, 0);
const totalCustomers = allProviders.reduce((sum, p) => sum + p.totalCustomers, 0);

const summary = {
  date: allProviders[0]?.date || new Date().toLocaleDateString(),
  totalProviders: allProviders.length,
  totalBookings: totalBookings,
  totalCustomers: totalCustomers,
  providers: allProviders.map(p => ({
    name: p.providerName,
    bookings: p.bookings.length,
    customers: p.totalCustomers
  })),
  reportGeneratedTime: new Date().toLocaleString()
};

return [{ json: summary }];
